code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double Davg, dmin;
        scanf("%lf %lf", &Davg, &dmin);
        double R = (3 * Davg - dmin) / 2;
        printf("%.4f\n", R);
    }
    return 0;
}

