import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            double Davg = sc.nextDouble();
            double dmin = sc.nextDouble();
            double R = (3 * Davg - dmin) / 2;
            System.out.printf("%.4f\n", R);
        }
    }
}

