const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [Davg, dmin] = readline().split(' ').map(Number);
    const R = (3 * Davg - dmin) / 2;
    console.log(R.toFixed(4));
}
